<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading" />

            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered modal-lg">
                    <div class="modal-content">

                        <div class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">{{ EditData.length > 0 ? $t('Update') : $t('Add') }}</h5>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;"
                                    role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                        class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con" v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                            <button type="button" class="close" @click="Close">
                                <em class="fa fa-times"></em>
                            </button>
                        </div>

                        <div class="modal-body">
                            <div class="row">
                                <!-- Client Field -->
                                <div class="col-lg-6">
                                    <div class="form-group">
                                        <label>{{ $t('SelectClient') }}:<span class="mandatory">*</span></label>
                                        <!-- <multiselect
                                        v-model="selectedClient"
                                        :options="clientList"
                                        :multiple="false"
                                        :searchable="true"
                                        label="text"
                                        track-by="value"
                                        placeholder="Select"
                                        :class="{ 'is-invalid': validationErrors.client }"
                                        @input="onClientChange"
                                        >
                                        </multiselect> -->
                                        <SearchableSelect
                                        v-model="selectedClient"
                                        :items="clientList"
                                        :max-visible-chips="3"
                                        :action-buttons="{ selectAll: true, active: true, inactive: true, clear: true }"
                                        :item-fields="['text']"
                                        :group-fields="['groupText']"
                                        :max-render-items="50"
                                        :lazy-load="true"
                                        placeholder="Select Clients..."
                                        :onChange="onClientChange"
                                        :min-search-length="0"
                                        :class="{ 'border-danger': validationErrors.client }"
                                        style="min-width: 300px"
                                        />
                                    </div>
                                </div>

                                <!-- Rule Name Field -->
                                <div class="col-lg-6">
                                    <div class="form-group">
                                        <label>{{ $t('BillingRuleName') }}:<span class="mandatory">*</span></label>
                                        <!-- <multiselect
                                        v-model="selectedRuleId"
                                        :options="billingRuleOptions"
                                        :multiple="false"
                                        :searchable="true"
                                        label="text"
                                        track-by="value"
                                        placeholder="Select"
                                        :class="{ 'is-invalid': validationErrors.ruleName }"
                                        @input="onRuleChange"
                                        >
                                       </multiselect> -->
                                       <SearchableSelect
                                        v-model="selectedRuleId"
                                        :items="billingRuleOptions"
                                        :max-visible-chips="3"
                                        :action-buttons="{ selectAll: true, active: true, inactive: true, clear: true }"
                                        :item-fields="['text']"
                                        :group-fields="['groupText']"
                                        :max-render-items="50"
                                        :lazy-load="true"
                                        placeholder="Select Bill..."
                                        :onChange="onRuleChange"
                                        :min-search-length="0"
                                        :class="{ 'border-danger': validationErrors.ruleName}"
                                        style="min-width: 300px"
                                        />
                                    </div>
                                </div>
                            </div>

                            <!-- Flag Conditions Section -->
                            <div class="col-lg-12 mb-2 mt-3 p-0">
                        <div class="heading-border mb-2">
                            <h5 class="h5">
                                <span>{{ $t('FlagCondition') }}</span>
                                <small class="float-right">
                                    <a href="javascript:;"  :class="['ancAddMoreFlag',showFlagConditions ? '': 'disabled']" :title="$t('AddAdditionalFlagCondition')" data-toggle-tooltip="tooltip" @click="AddAdditionalFlag">
                                        <i class="fa fa-plus pr-2">
                                    </i>{{ $t('AddAdditionalFlagCondition') }}</a>
                                </small>
                            </h5>
                        </div>
                     </div>
                            <div v-if="showFlagConditions" class="col-lg-12 manage-color mt-3 p-0">
                                <div v-for="(condition, index) in flagConditions" :key="condition.id" class="row mng-number mb-1 align-items-stretch mx-0 divclone" :data-index="condition.id">
                                    <div class="col-lg-1 bg-numbr p-3 text-center d-flex align-items-center">
                                        <h4 class="w-100">{{ index + 1 }}</h4>
                                    </div>
                                    <div class="col-lg-11 p-3">
                                        <div class="row">
                                            <div class="col-lg-12 mb-2">
                                                <div class="heading-border mb-2">
                                                    <h5 class="h5">
                                                        <span>{{$t('When')}}</span>
                                                        <small class="float-right">
                                                            <a href="javascript:;" class="delflagcondition" :style="flagConditions.length > 1 ? 'display:block;' : 'display:none;'" @click="deleteCondition(index)">
                                                                <i class="fa fa-trash pr-2"></i>{{ $t('Delete') }}
                                                            </a>
                                                        </small>
                                                    </h5>
                                                </div>
                                            </div>
                                            <div class="col-lg-10">
                                                <label>{{ $t('ServiceName') }}:<span class="mandatory">*</span></label>
                                                <div class="form-group">
                                                    <div class="input-group mb-3">
                                                        <select 
                                                            class="form-control" 
                                                            :class="{ 'is-invalid': condition.errors && condition.errors.serviceId }" 
                                                            v-model="condition.ServiceId" 
                                                            @change="handleTemplateChange(condition.ServiceId, 'SERVICE', index)"
                                                        >
                                                            <option value="">{{ $t('Select') }}</option>
                                                            <option v-for="(item) in ServiceList" :key="item.value" :value="item.value">
                                                                {{ item.name }}
                                                            </option>
                                                        </select>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="col-lg-2">
                                                <label>{{ $t('Status') }}:<span class="mandatory">*</span></label>
                                                <div class="form-group">
                                                    <div class="input-group mb-3">
                                                        <select 
                                                            class="form-control" 
                                                            :class="{ 'is-invalid': condition.errors && condition.errors.statusId }" 
                                                            v-model="condition.StatusId"
                                                        >
                                                            <option v-for="(item, idx) in StatusData" :key="idx" :value="item.STATUS_ID">
                                                                {{ item.STATUS }}
                                                            </option>
                                                        </select>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="col-lg-12 divthen">
                                                <div class="row">
                                                    <div class="col-lg-12 mb-2">
                                                        <div class="heading-border mb-2">
                                                            <h5 class="h5"><span>{{ $t('Then') }}</span></h5>
                                                        </div>
                                                    </div>

                                                    <div class="col-lg-12 divthenchange">
                                                        <div class="row divchange" v-for="(item, innerIndex) in condition.Mainleveldiv" :key="innerIndex">
                                                            <div class="col-lg-4">
                                                                <div class="form-group">
                                                                    <label>{{ $t('Change') }}:<span class="mandatory">*</span></label>
                                                                    <div class="input-group mb-3">
                                                                        <select 
                                                                            class="form-control" 
                                                                            :class="{ 'is-invalid': item.errors && item.errors.tempId }" 
                                                                            v-model="item.TempId" 
                                                                            @change="GetFlagFieldListDropdown(index, innerIndex, item.TempId)"
                                                                        >
                                                                            <option value="">{{ $t('Select') }}</option>
                                                                            <option v-for="(ch, idx) in ChangeFieldData" :key="idx" :value="ch.TEMPLATE_ID">
                                                                                {{ ch.DISPLAY_NAME }} ({{ch.DATA_TYPE }})
                                                                            </option>
                                                                        </select>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                            <div class="col-lg-4">
                                                                <div class="form-group">
                                                                    <label>{{ $t('To') }}:<span class="mandatory">*</span></label>
                                                                    <div class="input-group mb-3" v-if="!item.showTextFiled">
                                                                        <select 
                                                                            class="form-control" 
                                                                            :class="{ 'is-invalid': item.errors && item.errors.toId }" 
                                                                            v-model="item.ToId" 
                                                                            @change="UpdateSelectedToData(item)"
                                                                        >
                                                                            <option value="">{{ $t('Select') }}</option>
                                                                            <option v-for="(t, idx) in item.ToData" :key="idx" :value="t.VALUE">
                                                                                {{ t.NAME }}
                                                                            </option>
                                                                        </select>
                                                                    </div>
                                                                    <div class="input-group mb-3" v-if="item.showTextFiled">
                                                                        <input type="text" class="form-control" :class="{ 'is-invalid': item.errors && item.errors.toId}" />
                                                                    </div>
                                                                </div>
                                                            </div>
                                                            <div class="col-lg-2 mng-btn">
                                                                <label></label>
                                                                <div class="input-group">
                                                                    <em class="btn btn-primary mb-2" v-if="innerIndex === 0" @click="addRow(index)">
                                                                        <i class="fa fa-plus font-20 mt-1"></i>
                                                                    </em>
                                                                    <em class="btn btn-danger mb-2" v-if="innerIndex !== 0" @click="deleteRow(index, innerIndex)">
                                                                        <i class="fa fa-trash font-20 mt-1"></i>
                                                                    </em>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>

                                        </div>
                                    </div>

                                </div>
                            </div>
                                <div class="row flex-row-reverse mt-4">
                                   <div class="col-lg-6 text-right">
                                       <a href="javascript:;" title=""   :class="['btn btn-primary ancAddMoreFlag mr-1',showFlagConditions ? '': 'disabled']" style="" data-toggle-tooltip="tooltip" data-original-title="Add more flag condition" @click="AddAdditionalFlag">
                                        <i class="fa fa-plus pr-2"></i>{{ $t('AddAdditionalFlagCondition') }}</a>
                                       <a href="javascript:;" id="btnSaveFlagData" title="" class="btn btn-success mr-1" data-toggle-tooltip="tooltip" data-original-title="Save Rule" @click="SaveData">
                                        <i class="fa fa-save pr-2"></i>{{ $t('SaveRule') }}</a>
                                       <a title="" class="btn btn-danger"  data-toggle-tooltip="tooltip" data-original-title="Cancel"  @click="Close">
                                       <i class="fa fa-close pr-2">
                                       </i>{{ $t('Cancel') }}</a>
                                   </div>
                                   <div class="col-lg-6">
                                       <div class="py-2">
                                           <span class="mandatory">{{ $t('MandatoryString') }}</span>
                                       </div>
                                   </div>
                               </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../services/DataService';
import { locateBillingService } from '../../services/locateBillingService';
import SearchableSelect from '../Common/SearchableSelect.vue';
export default {
    components: {
        SearchableSelect
    },
    props: {
        EditData: {
            type: Array,
            required: false,
            default: () => []
        },
    },
    data() {
        return {
            isLoading: false,
            loadingCount: 0,
            clientList: [],
            selectedOption: null,
            billingRuleOptions: [],
            BillRule: [],
            ServiceList: [],
            StatusData: [],
            ChangeFieldData: [],
            selectedClient: null,
            validationErrors: {
              client: null,
              ruleName: null 
                },
            selectedRuleId: null,
            setupId: null,
            showFlagConditions: false,
            isShowUnit: true,
            isGroupBy: false,
            isComboChargeScope: false,
            validationErrors: {
                client: '',
                ruleName: ''
            },
            flagConditions: [{
                id: 0,
                ServiceId: '',
                StatusId: '1001',
                errors: {},
                Mainleveldiv: [{
                    TempId: '',
                    TEMPLATE_ID: "",
                    ToId: '',
                    NAME: '',
                    VALUE: null,
                    ToData: [],
                    errors: {}
                }]
            }],
        };
    },

    created: async function () {
        var vm = this;
        vm.GetStatusList();
        await vm.GetDDLCompanyContractClients();
        if (vm.EditData.length > 0 && vm.EditData[0].CLIENT_FLAG_ID > 0) {
         vm.selectedClient = Number(vm.clientList.find(element => Number(element.value) === vm.EditData[0].CLIENT_ID)?.value);
         await vm.onClientChange();
         vm.selectedRuleId = Number(vm.billingRuleOptions.find(element => Number(element.value) === vm.EditData[0].CONFIGURATION_ID)?.value);
            await vm.onRuleChange();
            setTimeout(() => {
                const groupedByService = {};
                vm.EditData.forEach(item => {
                    const serviceId = item.SERVICE_ID;
                    if (!groupedByService[serviceId]) {
                        groupedByService[serviceId] = {
                            ServiceId: serviceId,
                            StatusId: item.STATUS_ID,
                            items: []
                        };
                    }
                    groupedByService[serviceId].items.push(item);
                });
                const serviceIds = Object.keys(groupedByService);
                debugger
                vm.flagConditions = serviceIds.map((serviceId, index) => {
                    const group = groupedByService[serviceId];
                    return {
                        id: index,
                        ServiceId: group.ServiceId,
                        StatusId: group.StatusId,
                        errors: {},
                        Mainleveldiv: group.items.map(item => ({
                            TempId: Number(item.template_id),
                            TEMPLATE_ID: '',
                            ToId: item.FIELD_VALUE,
                            NAME: item.FIELD_NAME,
                            VALUE: null,
                            ToData: [],
                            errors: {},
                            showTextFiled:false
                        }))
                    };
                });
                vm.$nextTick(() => {
                    let templateNotFound = false;
                    vm.flagConditions.forEach((condition, conditionIndex) => {
                        condition.Mainleveldiv.forEach((row, rowIndex) => {
                            if (row.TempId) {
                                vm.GetFlagFieldListDropdown(conditionIndex, rowIndex, row.TempId, true);
                            }
                            else{
                                vm.ShowAlert(vm.$t('TemplatenotfoundPleasecontacttheadministrator', [vm.$t('Flag')]), "failure", true, vm.$t("Alert"));
                                templateNotFound = true;
                            }
                        });
                    });
                });
            }, 500);
        }
    },

    methods: {
        startLoading() {
            this.loadingCount++;
            this.isLoading = true;
        },
        
        stopLoading() {
            this.loadingCount--;
            if (this.loadingCount <= 0) {
                this.loadingCount = 0;
                this.isLoading = false;
            }
        },

        getUserGuideTitle() {
            let text = this.$t('USER_GUIDE_CLIENT_FLAG');
            return text
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },

        Close() {
            this.$emit('CloseAddFlag');
        },

        async onClientChange() {
            var vm = this;
            var clientId = vm.selectedClient;
            
            if (Array.isArray(clientId)) {
                clientId = clientId[0];
            }
            vm.validationErrors.client = '';
            if (!clientId || clientId === '') {
                vm.billingRuleOptions = [];
                vm.selectedRuleId = '';
                vm.showFlagConditions = false;
                return;
            }
            vm.startLoading();
            var url = `clientId=${clientId}`;
            try {
                const response = await DataService.GetBillingRuleByClient(url);
                if (response.data && response.data.result && response.data.result.length > 0) {
                    vm.BillRule = response.data.result;
                    vm.billingRuleOptions = vm.BillRule.map(itm => ({
                    value: Number( itm.CONFIGURATION_ID),
                    text: itm.BILLING_CONFIG_NAME             
                    }));
                } else {
                    vm.billingRuleOptions = [];
                    vm.selectedRuleId=[];
                }
            } catch (error) {
                vm.billingRuleOptions = [];
             vm.selectedRuleId=[];
            } finally {
                vm.stopLoading();
            }
        },

        async onRuleChange() {
            var vm = this;
            vm.validationErrors.ruleName = '';
            if (!vm.selectedRuleId || vm.selectedRuleId === '' || vm.selectedRuleId ===[]) {
                vm.showFlagConditions = false;
                return;
            }
            vm.showFlagConditions = true;
            try {
                await Promise.all([
                    vm.GetServiceList(vm.selectedRuleId),
                    vm.GetFieldsListBySetupId()
                ]);
            } catch (error) {
                console.error('Error loading flag form data:', error);
            }
        },

        async GetServiceList(ruleId) {
            var vm = this;
            vm.startLoading();
            vm.ServiceList = [];
            var url = `ruleId=${ruleId || 0}`;
            try {
                const response = await DataService.LoadFlagList(url);
                if (response && response.data && Array.isArray(response.data) && response.data.length > 0) {
                    vm.ServiceList = response.data.map(itm => ({
                        name: itm.Name || itm.name,
                        value: itm.Value || itm.value
                    }));
                } else {
                    vm.ServiceList = [];
                }
            } catch (error) {
                vm.ServiceList = [];
            } finally {
                vm.stopLoading();
            }
        },

        GetStatusList() {
            const vm = this;
            vm.startLoading();
            DataService.GetClientStatusList().then((response) => {
                const data = JSON.parse(response.data);
                if (data) {
                    vm.StatusData = data.filter(itm => itm.STATUS_ID === 1001 || itm.STATUS_ID === 1002);
                }
                vm.stopLoading();
            }).catch(error => {
                 vm.stopLoading();
            });
        },

        async GetDDLCompanyContractClients() {
            var vm = this;
            vm.startLoading();
            var url = `reqFrom=CUSTOM`;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList = response.data.items;
            } catch (error) {
                vm.clientList = [];
            } finally {
                vm.stopLoading();
            }
        },

        async GetFieldsListBySetupId() {
            var vm = this;
            vm.startLoading();
            var configid = parseFloat(vm.selectedRuleId);
            var selectedRule = vm.BillRule.find(x => x.CONFIGURATION_ID == configid);
            vm.setupId = selectedRule ? selectedRule.SETUP_ID : null;
            if (!vm.setupId) {
                vm.ChangeFieldData = [];
                vm.stopLoading();
                return;
            }
            var url = `setupId=${vm.setupId}&isShowUnit=${vm.isShowUnit}&isGroupBy=${vm.isGroupBy}&isComboChargeScope=${vm.isComboChargeScope}&reqFrom=flag`;
            try {
                const response = await DataService.GetFieldsListBySetupId(url);
                if (response.data && response.data.length > 0) {
                    vm.ChangeFieldData = JSON.parse(response.data);
                }
            } catch (error) {
                console.error('Error fetching fields list:', error);
                vm.ChangeFieldData = [];
            } finally {
                vm.stopLoading();
            }
        },

        AddAdditionalFlag() {
            const newCondition = {
                id: this.flagConditions.length,
                ServiceId: '',
                StatusId: '1001',
                errors: {},
                Mainleveldiv: [{
                    TempId: '',
                    TEMPLATE_ID: "",
                    ToId: '',
                    NAME: "",
                    VALUE: null,
                    ToData: [],
                    errors: {},
                    showTextFiled:false
                }]
            };
            this.flagConditions.push(newCondition);
        },

        deleteCondition(index) {
            var vm=this;
            vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("SERVICE")), function () {
             if (vm.flagConditions.length > 1) {
                vm.flagConditions.splice(index, 1);
            }
                });
           
        },

        addRow(conditionIndex) {
            this.flagConditions[conditionIndex].Mainleveldiv.push({
                TempId: '',
                TEMPLATE_ID: "",
                ToId: '',
                NAME: "",
                VALUE: null,
                ToData: [],
                errors: {}
            });
        },

        deleteRow(conditionIndex, rowIndex) {
            if (this.flagConditions[conditionIndex].Mainleveldiv.length > 1) {
                this.flagConditions[conditionIndex].Mainleveldiv.splice(rowIndex, 1);
            }
        },

        handleTemplateChange(data, type, conditionIndex) {
            debugger
            if (type === 'SERVICE') {
                if (this.flagConditions[conditionIndex].errors) {
                    this.flagConditions[conditionIndex].errors.serviceId = '';
                }
                let duplicateCount = 0;
                for (let i = 0; i < this.flagConditions.length; i++) {
                    const element = this.flagConditions[i];
                    if (element.ServiceId == data && data !== '') {
                        duplicateCount++;
                    }
                }
                if (duplicateCount > 1) {
                    this.ShowAlert(this.$t('DDLAlredySelectedValueMsg', [this.$t('Flag')]), "warning", true, this.$t("Alert"));
                    if (conditionIndex !== undefined) {
                        this.flagConditions[conditionIndex].ServiceId = '';
                    }
                    return;
                }
            }
        },    async handleOptionChange(row, rowIndex, item, conditionIndex) {
      const selectedValue = row.selectedOption;
      const conditions = [
        'tickettype', 'status', 'wd_desc', 'county', 'statuscode', 
        'status2', 'after_hours', 'is_unit_verified', 'district_code', 
        'utility_abbrev', 'state', 'sba_id'
      ];
      if (conditions.includes(selectedValue.toLowerCase())) {
        await this.LoadFlagFieldDropDown(row, rowIndex, conditionIndex, selectedValue);
      } else {
        
      }
    },
    showInputField(row) {
      return row.inputFieldVisible;
    },
    async LoadFlagFieldDropDown(row, rowIndex, conditionIndex, selectedValue) {
      const name = selectedValue;
      this.startLoading();

      try {
        const res = await DataService.GetFlagFieldListDropdown(`reqFrom=${name}`);
        const data = JSON.parse(res.data);
        this.flagConditions[conditionIndex].Mainleveldiv[rowIndex].ToData = data;
        if (!row.isEdit) {
          row.ToId = "";
          row.NAME = "";
          row.VALUE = "";
        } else {
          const selected = data.find(d => d.VALUE == row.ToId);
          if (selected) {
            row.NAME = selected.NAME;
            row.VALUE = selected.VALUE;
          }
        }
        this.stopLoading();
      } catch (error) {
        this.stopLoading();
      }
    },

        GetFlagFieldListDropdown(conditionIndex, rowIndex, templateId, isEdit = false) {
            const vm = this;
            debugger
            const rule = vm.ChangeFieldData.find(x => x.TEMPLATE_ID == templateId);
            debugger
            
            const name = rule ? rule.DISPLAY_NAME  : null;

            if (!vm.flagConditions[conditionIndex] || !vm.flagConditions[conditionIndex].Mainleveldiv[rowIndex]) {
                console.error('Invalid condition or row index');
                return;
            }
            const selectedValue = rule.COLUMN_NAME;
                const conditions = [
                    'tickettype', 'status', 'wd_desc', 'county', 'statuscode', 
                    'status2', 'after_hours', 'is_unit_verified', 'district_code', 
                    'utility_abbrev', 'state', 'sba_id'
                ];
                if (conditions.includes(selectedValue.toLowerCase())) {
                    const targetRow = vm.flagConditions[conditionIndex].Mainleveldiv[rowIndex];
                    targetRow.showTextFiled=false;
                } else {
                    const targetRow = vm.flagConditions[conditionIndex].Mainleveldiv[rowIndex];
                    targetRow.showTextFiled=true;
                }
            const targetRow = vm.flagConditions[conditionIndex].Mainleveldiv[rowIndex];
            if (targetRow.errors) {
                targetRow.errors.tempId = '';
            }
            vm.startLoading();
            DataService.GetFlagFieldListDropdown(`reqFrom=${name}`).then(res => {
                const data = JSON.parse(res.data);
                targetRow.ToData = data;
                
                if (!isEdit) {
                    targetRow.ToId = "";
                    targetRow.NAME = "";
                    targetRow.VALUE = "";
                } else {
                    const selected = data.find(d => d.VALUE == targetRow.ToId);
                    if (selected) {
                        targetRow.NAME = selected.NAME;
                        targetRow.VALUE = selected.VALUE;
                    }
                }
                vm.stopLoading();
            }).catch(error => {
                vm.stopLoading();
            });
        },

        UpdateSelectedToData(item) {
            if (item.errors) {
                item.errors.toId = '';
            }
            const selected = item.ToData.find(t => t.VALUE == item.ToId);
            if (selected) {
                item.NAME = selected.NAME;
                item.VALUE = selected.VALUE;
            } else {
                item.NAME = "";
                item.VALUE = "";
            }
        },

        validateForm() {
            var vm = this;
            var isValid = true;
            if (!vm.selectedClient || vm.selectedClient === '') {
                vm.$set(vm.validationErrors, 'client', vm.$t('Required'));
                isValid = false;
            } else {
                vm.$set(vm.validationErrors, 'client', '');
            }
            if (!vm.selectedRuleId || vm.selectedRuleId === '') {
                vm.$set(vm.validationErrors, 'ruleName', vm.$t('Required'));
                isValid = false;
            } else {
                vm.$set(vm.validationErrors, 'ruleName', '');
            }
            if (vm.showFlagConditions) {
                vm.flagConditions.forEach((condition, conditionIndex) => {
                    if (!condition.errors) {
                        vm.$set(condition, 'errors', {});
                    }
                    if (!condition.ServiceId || condition.ServiceId === '') {
                        vm.$set(condition.errors, 'serviceId', vm.$t('Required'));
                        isValid = false;
                    } else {
                        vm.$set(condition.errors, 'serviceId', '');
                    }
                    if (!condition.StatusId || condition.StatusId === '') {
                        vm.$set(condition.errors, 'statusId', vm.$t('Required'));
                        isValid = false;
                    } else {
                        vm.$set(condition.errors, 'statusId', '');
                    }
                    condition.Mainleveldiv.forEach((row, rowIndex) => {

                        if (!row.errors) {
                            vm.$set(row, 'errors', {});
                        }
                        if (!row.TempId || row.TempId === '') {
                            vm.$set(row.errors, 'tempId', vm.$t('Required'));
                            isValid = false;
                        } else {
                            vm.$set(row.errors, 'tempId', '');
                        }
                        if (!row.ToId || row.ToId === '') {
                            vm.$set(row.errors, 'toId', vm.$t('Required'));
                            isValid = false;
                        } else {
                            vm.$set(row.errors, 'toId', '');
                        }
                    });
                });
            }
            vm.$forceUpdate();
            return isValid;
        },

 async SaveData() {
    var vm = this;
    if (!vm.validateForm()) {
        vm.ShowAlert(vm.$t("CorrectHighlightedErrors"), "failure", vm.$t('Alert'));
        return;
    }

    let clientFlagId = 0; 
    if (vm.EditData.length > 0) {
        const matchingEdit = vm.EditData.find(e => e.SERVICE_ID == vm.flagConditions[0].ServiceId);  
        if (matchingEdit) {
            clientFlagId = matchingEdit.CLIENT_FLAG_ID;  
        }
    }
  var parentData =[];
    const allConditionsData = vm.flagConditions.reduce((acc, condition) => {
        if(parentData == {} || parentData == '' || parentData ==[]){
         parentData = {
            ClientFlagId: clientFlagId, 
            ClientId: Number(vm.selectedClient) || 0,
            RoleId: Number(vm.selectedRuleId) || 0,
            ServiceId: String(condition.ServiceId || ''),
            SetupId: Number(vm.setupId) || 0,
            Status: condition.StatusId || 1001,
            Mainleveldiv: [] 
        };
        }

        let existingParent = acc.find(item => item.ServiceId === parentData.ServiceId);

        if (existingParent) {
            existingParent.Mainleveldiv.push(...condition.Mainleveldiv.map(row => ({
                TempId: row.TempId,
                TEMPLATE_ID: row.TEMPLATE_ID || '',
                ToId: row.ToId || '',
                NAME: row.NAME,
                VALUE: row.VALUE,
                ServiceId: String(condition.ServiceId),
                StatusId: row.StatusId || 1001
            })));
        } else {
            parentData.Mainleveldiv.push(...condition.Mainleveldiv.map(row => ({
                TempId: row.TempId,
                TEMPLATE_ID: row.TEMPLATE_ID || '',
                ToId: row.ToId || '',
                NAME: row.NAME,
                VALUE: row.VALUE,
                ServiceId: String(condition.ServiceId),
                StatusId: row.StatusId || 1001
            })));
            acc.push(parentData); 
        }

        return acc;
    }, []);
    var obj = JSON.stringify(allConditionsData);

    vm.startLoading();
    try {
        const response = await DataService.SaveUpdateFlagData(obj);
        if (response.data != null) {
            const Result = JSON.parse(response.data)[0];
            if (Result.Success == 1) {
                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Flag')]), "success", true, vm.$t("Alert"));
                vm.Close();
            } else if (Result.Success == 2) {
                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Flag')]), "success", true, vm.$t('Alert'));
                vm.Close();
            } else if (Result.Success == 0 && Result.Error == 'EXISTS') {
                vm.ShowAlert(vm.$t('AlreadyExistsThisContract', [vm.$t('Flag')]), "warning", true, vm.$t("Alert"));
            } else {
                vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
            }
        }
    } catch (error) {
        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
    } finally {
        vm.stopLoading();
    }
}

 }
};
</script>
